INSERT INTO gencine_hadiths (sort_order, title, ar, ku, source, active) VALUES
  (96, 'نیشانێن منافقان', 'عَنْ عَبْدِ الله بْنِ عَمْرٍو رضي الله عنه أَنَّ النَّبِيَّﷺ قَالَ: «أَرْبَعٌ مَنْ كُنَّ فِيهِ كَانَ مُنَافِقًا خَالِصًا، وَمَنْ كَانَتْ فِيهِ خَصْلَةٌ مِنْهُنَّ كَانَتْ فِيهِ خَصْلَةٌ مِنَ النِّفَاقِ حَتَّى يَدَعَهَا: إِذَا اؤْتُمِنَ خَانَ، وَإِذَا حَدَّثَ كَذَبَ، وَإِذَا عَاهَدَ غَدَرَ، وَإِذَا خَاصَمَ فَجَرَ».', 'عه‌بدللاهێ كوڕێ عه‌مرێ كوڕێ عاصى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: چار سالۆخه‌ت هه‌نه‌ هه‌چییێ ئه‌و ل نك هه‌بن ئه‌و خوڕى منافقه‌، و هه‌چییێ ئێك ژ وان سالۆخه‌تان ل نك هه‌بت ئه‌وى سالۆخه‌ته‌كێ نیفاقێ ل نك هه‌یه‌: ئه‌گه‌ر ئێكى باوه‌رییا خۆ پێ ئینا ئه‌و خیانه‌تێ بكه‌ت، و ئه‌گه‌ر ئه‌و ئاخفت ئه‌و دره‌وێ بكه‌ت، و ئه‌گه‌ر وى په‌یمانه‌ك دا ئه‌و غه‌درێ بكه‌ت، و ئه‌گه‌ر وى هه‌ڤڕكى كر ئه‌و د سه‌ردادچت.', NULL, true),
  (106, 'نیشانێن منافقان', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه عَنِ النَّبِيِّﷺ قَالَ: «آيَةُ المُنَافِقِ ثَلاَثٌ: إِذَا حَدَّثَ كَذَبَ، وَإِذَا وَعَدَ أَخْلَفَ، وَإِذَا اؤْتُمِنَ خَانَ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: نیشانێن منافقى سێنه‌: ئه‌گه‌ر ئه‌و ئاخفت ئه‌و دره‌وێ بكه‌ت، و ئه‌گه‌ر وى په‌یمانه‌ك دا ئه‌و غه‌درێ بكه‌ت، و ئه‌گه‌ر ئێكى باوه‌رییا خۆ پێ ئینا ئه‌و خیانه‌تێ بكه‌ت.', NULL, true),
  (116, 'ڕاستى ڕێكا بەحەشتێیه و درەو ڕێكا جەهنەمێیه', 'عَنْ عَبْدِ الله بن مسعود رضي الله عنه قَالَ: قَالَ رَسُولُ اللهﷺ : «عَلَيْكُمْ بِالصِّدْقِ، فَإِنَّ الصِّدْقَ يَهْدِي إِلَى الْبِرِّ، وَإِنَّ الْبِرَّ يَهْدِي إِلَى الجَنَّةِ، وَمَا يَزَالُ الرَّجُلُ يَصْدُقُ وَيَتَحَرَّى الصِّدْقَ حَتَّى يُكْتَبَ عِنْدَ الله صِدِّيقًا، وَإِيَّاكُمْ وَالْكَذِبَ، فَإِنَّ الْكَذِبَ يَهْدِي إِلَى الْفُجُورِ، وَإِنَّ الْفُجُورَ يَهْدِي إِلَى النَّارِ، وَمَا يَزَالُ الرَّجُلُ يَكْذِبُ وَيَتَحَرَّى الْكَذِبَ حَتَّى يُكْتَبَ عِنْدَ الله كَذَّابًا».', 'عه‌بدللاهێ كوڕێ مه‌سعوودى‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: وه‌ ئێمانه‌ت ڕاستى، چونكى هندى ڕاستییه‌ به‌رێ خودانى دده‌ته‌ قه‌نجییێ، و هندى قه‌نجییه‌ به‌رێ وى دده‌ته‌ به‌حه‌شتێ، و زه‌لام دێ مینت ڕاستییێ بێژت و ل ڕاستییێ گه‌ڕیێت حه‌تا ئه‌و ل نك خودێ دئێته‌ نڤیسین پڕڕاستگۆ، و هشیارى دره‌وێ بن، چونكى هندى دره‌وه‌ به‌رێ خودانى دده‌ته‌ سه‌رداچوونێ، و سه‌رداچوون به‌رێ وى دده‌ته‌ ئاگرى، و زه‌لام دێ مینت دره‌وێ كه‌ت و ل دره‌وێ گه‌ڕیێت حه‌تا ئه‌و ل نك خودێ دئێته‌ نڤیسین پڕدره‌وین.', NULL, true),
  (126, 'خرابترین مرۆڤ كەسێ دوڕوییه', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه عَنْ رَسُولِ اللهﷺ قَالَ: «تَجِدُونَ النَّاسَ مَعَادِنَ، خِيَارُهُمْ فِي الجَاهِلِيَّةِ خِيَارُهُمْ فِي الإِسْلاَمِ إِذَا فَقِهُوا، وَتَجِدُونَ خَيْرَ النَّاسِ فِي هَذَا الشَّأْنِ أَشَدَّهُمْ لَهُ كَرَاهِيَةً، وَتَجِدُونَ شَرَّ النَّاسِ ذَا الْوَجْهَيْنِ، الَّذِي يَأْتِي هَؤُلاَءِ بِوَجْهٍ وَيَأْتِي هَؤُلاَءِ بِوَجْهٍ».', 'ئه‌بوو هوره‌یره‌‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: هوین دبینن مرۆڤ مه‌عده‌نن (یه‌عنى: د بناخه‌یێ خۆ دا ئه‌و دژێك جودانه‌) باشێ وان د جاهلییه‌تێ دا باشێ وانه‌ د ئیسلامێ دا ئه‌گه‌ر زانابوو، و هوین دبینن باشترینێ مرۆڤان بۆ ڤى كارى (یه‌عنى: مه‌زنى و به‌رپڕسییێ) ئه‌وه‌ یێ ژ هه‌مییان پتر ئه‌و نه‌ڤێت، و هوین دبینن خرابترینێ مرۆڤان دوڕوییه‌، ئه‌وێ ب ڕوییه‌كێ دئێته‌ نك ڤان، و ب ڕوییه‌كى دئێته‌ نك ڤان.', NULL, true),
  (136, 'خودێ ل دویڤ زۆردارى بەرددەت حەتا وى دگرت', 'عَنْ أَبِي موسى رضي الله عنه قَالَ: قال رَسُولُ اللهﷺ : «إِنَّ الله لَيُمْلِي لِلظَّالِمِ حَتَّى إِذَا أَخَذَهُ لَمْ يُفْلِتْهُ» قَالَ: ثُمَّ قَرَأَ: «وَكَذَٰلِكَ أَخۡذُ رَبِّكَ إِذَآ أَخَذَ ٱلۡقُرَىٰ وَهِيَ ظَٰلِمَةٌۚ إِنَّ أَخۡذَهُۥٓ أَلِيمٞ شَدِيدٌ ١٠٢».', 'ئه‌بوو هوره‌یره‌‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: هندى خودێیه‌ ل دویڤ زۆردارى به‌ردده‌ت، حه‌تا ئه‌گه‌ر وى ئه‌و گرت ئه‌و ژێ خلاص نابت، پاشى وى ئه‌ڤ ئایه‌ته‌ خواند ئه‌وا تێدا هاتى: گرتنا خودایێ ته‌ ب خه‌لكێ باژێڕان یا هۆسایه‌ ده‌مێ ئه‌و زۆردارییێ دكه‌ن، هندى گرتنا وییه‌ یا ب ئێش و دژواره‌.', NULL, true),
  (146, 'پشتەڤانییا ته بۆ زۆردارى ئەوه تو نەهێلى ئەو زۆردارییێ بكەت', 'عَنْ أَنَسٍ رضي الله عنه قَالَ: قَالَ رَسُولُ اللهﷺ : «انْصُرْ أَخَاكَ ظَالِمًا، أَوْ مَظْلُومًا» فَقَالَ رَجُلٌ: يَا رَسُولَ الله، أَنْصُرُهُ إِذَا كَانَ مَظْلُومًا أَفَرَأَيْتَ إِذَا كَانَ ظَالِمًا كَيْفَ أَنْصُرُهُ؟ قَالَ: «تَحْجُزُهُ، أَوْ تَمْنَعُهُ مِنَ الظُّلْمِ فَإِنَّ ذَلِكَ نَصْرُهُ».', 'ئه‌نه‌س -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: تو پشته‌ڤانییا برایێ خۆ بكه‌ چ ئه‌و یێ زۆردار بت، چ زۆردارى لێ هاتبته‌كرن. زه‌لامه‌كى گۆت: ئه‌ى پێغه‌مبه‌رێ خودێ، ئه‌ز دێ پشته‌ڤانییا وى كه‌م ئه‌گه‌ر زۆردارى ل وى هاتبته‌كرن، به‌لێ پا ئه‌گه‌ر ئه‌و یێ زۆردار بت، چاوا ئه‌ز دێ پشته‌ڤانییا وى كه‌م؟ وى گۆت: تو دێ وى ژ زۆردارییێ گرى ئه‌وه‌ پشته‌ڤانییا ته‌ بۆ وى.', NULL, true),
  (156, 'موسلمانێ دورست كیە؟ و مشەختێ دورست كیە؟', 'عَنْ عَبْدِ الله بْنِ عَمْرٍو رضي الله عنه عَنِ النَّبِيِّﷺ قَالَ : «المُسْلِمُ مَنْ سَلِمَ المُسْلِمُونَ مِنْ لِسَانِهِ وَيَدِهِ، وَالمُهَاجِرُ مَنْ هَجَرَ مَا نَهَى الله عَنْهُ».', 'عه‌بدللاهێ كوڕێ عه‌مرى -خودێ ژ هه‌ردویان رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: موسلمان ئه‌وه‌ یێ موسلمان ژ ئه‌زمانێ وى و ده‌ستێ وى دپارستى بن، و مشه‌خت ئه‌وه‌ یێ پشت بده‌ته‌ وى یێ یێ خودێ نه‌هى ژێ كرى.', NULL, true),
  (166, 'سالۆخەتێن موسلمانێ دورست', 'عَنِ عَبْدِ الله بْنِ عُمَرَ رضي الله عنه أَنَّ رَسُولَ اللهﷺ قَالَ: «المُسْلِمُ أَخُو المُسْلِمِ لاَ يَظْلِمُهُ، وَلاَ يُسْلِمُهُ، وَمَنْ كَانَ فِي حَاجَةِ أَخِيهِ كَانَ الله فِي حَاجَتِهِ، وَمَنْ فَرَّجَ عَنْ مُسْلِمٍ كُرْبَةً فَرَّجَ الله عَنْهُ كُرْبَةً مِنْ كُرُبَاتِ يَوْمِ الْقِيَامَةِ، وَمَنْ سَتَرَ مُسْلِمًا سَتَرَهُ الله يَوْمَ الْقِيَامَةِ».', 'عه‌بدللاهێ كوڕێ عومه‌رى -خودێ ژ هه‌ردویان رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: موسلمان برایێ موسلمانییه‌ زۆردارییێ لێ ناكه‌ت، و وى ته‌سلیمى دوژمنى ناكه‌ت، و هه‌چییێ د خێرا برایێ خۆ دا بت خودێ دێ د خێرا وى دا بت، و هه‌چییێ ته‌نگاڤییه‌كێ ژ سه‌ر موسلمانه‌كى ڕاكه‌ت خودێ ته‌نگاڤییه‌كێ ژ ته‌نگاڤییێن ڕۆژا قیامه‌تێ دێ ژ سه‌ر وى ڕاكه‌ت، و هه‌چییێ موسلمانه‌كى ستاره‌ بكه‌ت ڕۆژا قیامه‌تێ خودێ دێ وى ستاره‌ كه‌ت.', NULL, true),
  (176, 'حەفت ئەمر و حەفت نەهى', 'قَالَ الْبَرَاءُ بْنُ عَازِبٍ رضي الله عنه : أَمَرَنَا النَّبِيُّﷺ بِسَبْعٍ وَنَهَانَا عَنْ سَبْعٍ، أَمَرَنَا بِعِيَادَةِ المَرِيضِ، وَاتِّبَاعِ الْجِنَازَةِ، وَتَشْمِيتِ الْعَاطِسِ، وَإِبْرَارِ الْقَسَمِ، وَنَصْرِ المَظْلُومِ، وَإِفْشَاءِ السَّلاَمِ، وَإِجَابَةِ الدَّاعِي، وَنَهَانَا عَنْ خَوَاتِيمِ الذَّهَبِ، وَعَنْ آنِيَةِ الْفِضَّةِ، وَعَنِ المَيَاثِرِ، وَالْقَسِّيَّةِ، وَالإِسْتَبْرَقِ، وَالدِّيبَاجِ.', 'به‌ررائێ كوڕێ عازبى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- فه‌رمان ب حه‌فت تشتان ل مه‌ كر، و ئه‌م ژ حه‌فت تشتان داینه‌ پاش، وى فه‌رمان ب سه‌ره‌دانا نه‌خۆشان ل مه‌ كر و دویكه‌فتنا جه‌نازه‌یان، و به‌رسڤدانا وى یێ دبێنژت، و نه‌شكاندنا سویندا وى یێ مرۆڤى دده‌ته‌ سویندێ، و پشته‌ڤانییا وى یێ سته‌م لێ دئێته‌كرن، و به‌لاڤكرنا سلاڤێ، و چوونا د به‌رسڤا وى یێ مرۆڤى ڤه‌خوینت، و وى ئه‌م ل به‌رخۆكرنا گوستیركێن زێڕى داینه‌ پاش، و خوارنا د ئامانێن زیڤى دا، و جلێن ده‌واران ئه‌وێن ژ ئاڤرمیشى دئێنه‌ چێكرن، و كراسێن ئاڤرمیشى، و كراسێن ئیسته‌بره‌ق و دیباجى (و ئه‌و ژى دو ڕه‌نگێن ئاڤرمیشینه‌).', NULL, true),
  (186, 'خودان باوەر خودان باوەرى دگرت', 'عَنْ أَبِي مُوسَى رضي الله عنه عَنِ النَّبِيِّﷺ قَالَ: «إِنَّ المُؤْمِنَ لِلْمُؤْمِنِ كَالْبُنْيَانِ يَشُدُّ بَعْضُهُ بَعْضًا» وَشَبَّكَ أَصَابِعَهُ.', 'ئه‌بوو مووسا -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: خودان باوه‌ر بۆ خودان باوه‌رى وه‌كى ئاڤاهییه‌ هنده‌ك هنده‌كێ دگرت. و وى تبلێن خۆ كرنه‌ د ناڤێك ڕا.', NULL, true),
  (196, 'مەتەلا خودان باوەران', 'عَنِ النُّعْمَانِ بْنِ بَشِيرٍ رضي الله عنه قَالَ: قَالَ رَسُولُ اللهﷺ : «مَثَلُ المُؤْمِنِينَ فِي تَوَادِّهِمْ، وَتَرَاحُمِهِمْ، وَتَعَاطُفِهِمْ، مَثَلُ الجَسَدِ إِذَا اشْتَكَى مِنْهُ عُضْوٌ تَدَاعَى لَهُ سَائِرُ الجَسَدِ بِالسَّهَرِ وَالحُمَّى».', 'نوعمانێ كوڕێ به‌شیرى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: مه‌ته‌لا خودان باوه‌ران د ڤیان و ره‌حم و دلۆڤانییا وان دا، وه‌كى مه‌ته‌لا له‌شییه‌، ئه‌گه‌ر ئه‌ندامه‌ك ژێ ئێشا له‌ش هه‌مى تاگرتى دبت و خه‌و ب چاڤان ناكه‌ڤت.', NULL, true),
  (206, 'دو ڕەنگێن دورست یێن حەسویدییێ', 'عَنْ عَبْدِ الله بْنِ مَسْعُودٍ رضي الله عنه يَقُولُ: قَالَ رَسُولُ اللهﷺ : «لاَ حَسَدَ إِلاَّ فِي اثْنَتَيْنِ: رَجُلٌ آتَاهُ الله مَالاً، فَسَلَّطَهُ عَلَى هَلَكَتِهِ فِي الحَقِّ، وَرَجُلٌ آتَاهُ الله حِكْمَةً، فَهُوَ يَقْضِي بِهَا وَيُعَلِّمُهَا».', 'عه‌بدللاهێ كوڕێ مه‌سعوودى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: حه‌سویدى چێ نابت، یا دو مرۆڤان تێ نه‌بت: زه‌لامه‌كى خودێ ماله‌كێ دایێ ڤێجا ئه‌و وى د حه‌قییێ دا خه‌رج دكه‌ت، و زه‌لامه‌كى خودێ زانینا (قورئانێ) یا دایێ ڤێجا ئه‌و حوكمى پێ دكه‌ت، و وێ نیشا خه‌لكى دده‌ت.', NULL, true),
  (216, 'ژ سالۆخەتێن بەحەشتى و جەهنەمییان', 'عَن حَارِثَةَ بْنِ وَهْبٍ الخُزَاعِيِّ رضي الله عنه قَالَ: سَمِعْتُ النَّبِيَّﷺ يَقُولُ: «أَلَا أُخْبِرُكُمْ بِأَهْلِ الجَنَّةِ؟ كُلُّ ضَعِيفٍ مُتَضَعِّفٍ لَوْ أَقْسَمَ عَلَى الله لَأَبَرَّهُ، أَلَا أُخْبِرُكُمْ بِأَهْلِ النَّارِ؟ كُلُّ عُتُلٍّ جَوَّاظٍ مُسْتَكْبِرٍ».', 'حارثه‌یێ كوڕێ وه‌هه‌بێ خوزاعى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ئه‌رێ ئه‌ز بۆ هه‌وه‌ به‌حسێ به‌حه‌شتییان نه‌كه‌م كینه‌؟ هه‌ر لاوه‌زه‌كێ خه‌لك وى لاواز دبینن، ئه‌گه‌ر ئه‌و خودێ بده‌ته‌ سویندێ خودێ سویندا وى دێ ب جهـ ئینت، و ئه‌ز بۆ هه‌وه‌ به‌حسێ جه‌هنه‌مییان نه‌كه‌م؟ هه‌ر كه‌سێ زڤڕ و ڕه‌ق و خۆ مه‌زن دكه‌ت.', NULL, true),
  (226, 'دا كو نعمەتا خودێ كێم نەكەى', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه قَالَ: قَالَ رَسُولُ اللهﷺ : «انْظُرُوا إِلَى مَنْ أَسْفَلَ مِنْكُمْ، وَلاَ تَنْظُرُوا إِلَى مَنْ هُوَ فَوْقَكُمْ، فَهُوَ أَجْدَرُ أَنْ لاَ تَزْدَرُوا نِعْمَةَ الله».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: به‌رێ خۆ بده‌نه‌ یێن د بن خۆ دا، و به‌رێ خۆ نه‌ده‌نه‌ یێن د سه‌ر خۆ دا، ئه‌و هه‌ژیتره‌ كو هوین نعمه‌تا خودێ كێم نه‌كه‌ن.', NULL, true),
  (236, 'دو گونەهێن مرۆڤ د قەبرى دا پێ دئێته عەزابدان', 'عَنْ ابْنِ عَبَّاسٍ رضي الله عنه قَالَ مَرَّ النَّبِيُّﷺ بِقَبْرَيْنِ فَقَالَ: «إِنَّهُمَا لَيُعَذَّبَانِ وَمَا يُعَذَّبَانِ فِي كَبِيرٍ، أَمَّا أَحَدُهُمَا فَكَانَ لَا يَسْتَتِرُ مِنْ الْبَوْلِ، وَأَمَّا الْآخَرُ فَكَانَ يَمْشِي بِالنَّمِيمَةِ».', 'ئبن عه‌بباس -خودێ ژ هه‌ردویان رازى بت- دبێژت: پێغه‌مبه‌ر -سلاڤ لێ بن- د به‌ر دو قه‌بران ڕا بۆرى، و گۆت: ئه‌و هه‌ردو یێن دئێنه‌ عه‌زابدان، و ئه‌و نه‌ ژ به‌ر تشته‌كێ مه‌زن دئێنه‌ عه‌زابدان، ئێك ژ وان خۆ ژ ده‌سنڤێژا زراڤ نه‌دپاراست، و یێ دى قه‌سه‌ ڤه‌دگوهازتن.', NULL, true),
  (246, 'قەسەڤەگوهێز ناچته بەحەشتێ', 'قَالَ حُذَيْفَةُ رضي الله عنه : سَمِعْتُ رَسُولَ اللهﷺ يَقُولُ: «لاَ يَدْخُلُ الجَنَّةَ نَمَّامٌ».', 'حوذه‌یفه‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: قه‌سه‌ڤه‌گوهێز ناچته‌ به‌حه‌شتێ.
